    type nonrec t =
      {
      name: NameString.t [@ocaml.doc "Name of the workflow to be updated."];
      description: WorkflowDescriptionString.t option
        [@ocaml.doc "The description of the workflow."];
      defaultRunProperties: WorkflowRunProperties.t option
        [@ocaml.doc
          "A collection of properties to be used as part of each execution of the workflow. Run properties may be logged. Do not pass plaintext secrets as properties. Retrieve secrets from a Glue Connection, Amazon Web Services Secrets Manager or other secret management mechanism if you intend to use them within the workflow run."];
      maxConcurrentRuns: NullableInteger.t option
        [@ocaml.doc
          "You can use this parameter to prevent unwanted multiple updates to data, to control costs, or in some cases, to prevent exceeding the maximum number of concurrent runs of any of the component jobs. If you leave this parameter blank, there is no limit to the number of concurrent workflow runs."]}
    let context_ = "UpdateWorkflowRequest"
    let make ?description =
      fun ?defaultRunProperties ->
        fun ?maxConcurrentRuns ->
          fun ~name ->
            fun () ->
              { description; defaultRunProperties; maxConcurrentRuns; name }
    let to_value x =
      structure_to_value
        [("Name", (Some (NameString.to_value x.name)));
        ("Description",
          (Option.map x.description ~f:WorkflowDescriptionString.to_value));
        ("DefaultRunProperties",
          (Option.map x.defaultRunProperties
             ~f:WorkflowRunProperties.to_value));
        ("MaxConcurrentRuns",
          (Option.map x.maxConcurrentRuns ~f:NullableInteger.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let maxConcurrentRuns =
        (Option.map ~f:NullableInteger.of_xml)
          (Xml.child xml_arg0 "MaxConcurrentRuns") in
      let defaultRunProperties =
        (Option.map ~f:WorkflowRunProperties.of_xml)
          (Xml.child xml_arg0 "DefaultRunProperties") in
      let description =
        (Option.map ~f:WorkflowDescriptionString.of_xml)
          (Xml.child xml_arg0 "Description") in
      let name =
        NameString.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Name") in
      make ?maxConcurrentRuns ?defaultRunProperties ?description ~name ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let maxConcurrentRuns =
        field_map json__ "MaxConcurrentRuns" NullableInteger.of_json in
      let defaultRunProperties =
        field_map json__ "DefaultRunProperties" WorkflowRunProperties.of_json in
      let description =
        field_map json__ "Description" WorkflowDescriptionString.of_json in
      let name = field_map_exn json__ "Name" NameString.of_json in
      make ?maxConcurrentRuns ?defaultRunProperties ?description ~name ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "Updates an existing workflow."]
module UpdateWorkflowResponse =
  struct
    type nonrec t =
      {
      name: NameString.t option
        [@ocaml.doc "The name of the workflow which was specified in input."]}
    type nonrec error =
      [
        `ConcurrentModificationException of ConcurrentModificationException.t 
      | `EntityNotFoundException of EntityNotFoundException.t 
      | `InternalServiceException of InternalServiceException.t 
      | `InvalidInputException of InvalidInputException.t 
      | `OperationTimeoutException of OperationTimeoutException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?name = fun () -> { name }
    let error_of_json name json =
      match name with
      | "ConcurrentModificationException" ->
          `ConcurrentModificationException
            (ConcurrentModificationException.of_json json)
      | "EntityNotFoundException" ->
          `EntityNotFoundException (EntityNotFoundException.of_json json)
      | "InternalServiceException" ->
          `InternalServiceException (InternalServiceException.of_json json)
      | "InvalidInputException" ->
          `InvalidInputException (InvalidInputException.of_json json)
      | "OperationTimeoutException" ->
          `OperationTimeoutException (OperationTimeoutException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ConcurrentModificationException" ->
          `ConcurrentModificationException
            (ConcurrentModificationException.of_xml xml)
      | "EntityNotFoundException" ->
          `EntityNotFoundException (EntityNotFoundException.of_xml xml)
      | "InternalServiceException" ->
          `InternalServiceException (InternalServiceException.of_xml xml)
      | "InvalidInputException" ->
          `InvalidInputException (InvalidInputException.of_xml xml)
      | "OperationTimeoutException" ->
          `OperationTimeoutException (OperationTimeoutException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ConcurrentModificationException e ->
          `Assoc
            [("error", (`String "ConcurrentModificationException"));
            ("details", (ConcurrentModificationException.to_json e))]
      | `EntityNotFoundException e ->
          `Assoc
            [("error", (`String "EntityNotFoundException"));
            ("details", (EntityNotFoundException.to_json e))]
      | `InternalServiceException e ->
          `Assoc
            [("error", (`String "InternalServiceException"));
            ("details", (InternalServiceException.to_json e))]
      | `InvalidInputException e ->
          `Assoc
            [("error", (`String "InvalidInputException"));
            ("details", (InvalidInputException.to_json e))]
      | `OperationTimeoutException e ->
          `Assoc
            [("error", (`String "OperationTimeoutException"));
            ("details", (OperationTimeoutException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Name", (Option.map x.name ~f:NameString.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let name =
        (Option.map ~f:NameString.of_xml) (Xml.child xml_arg0 "Name") in
      make ?name ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let name = field_map json__ "Name" NameString.of_json in make ?name ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "Updates an existing workflow."]